/* ===== PSIKOREALIS - PETA DIRI - SCRIPT ===== */ /* Tool ini TIDAK mengumpulkan data ke server manapun. Semua baca/tulis murni localStorage HP pengguna sendiri. */ (function () { 'use strict'; /* ---------- ICON SET (inline SVG, sesuai aturan: tidak boleh emoji) ---------- */ var ICON = { map: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><path d="M9 4L3 6.5v13L9 17l6 2.5 6-2.5v-13l-6 2.5L9 4z"/><path d="M9 4v13"/><path d="M15 6.5v13"/></svg>', spark: '<svg viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l1.8 6.2L20 10l-6.2 1.8L12 18l-1.8-6.2L4 10l6.2-1.8L12 2z"/></svg>', check: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>', arrow: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>', leaf: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8"><path d="M12 21c-4-2-8-6-8-11a8 8 0 0116 0c0 5-4 9-8 11z"/></svg>' }; /* ---------- DAFTAR TOOLS (sumber pola dari 6 tools + 1 tool 2-dimensi) ---------- */ /* url dikosongkan sengaja untuk roda_emosi, isi manual saat deploy */ var TOOLS = [ { slug: 'overthinking', label: 'Peta Pola Overthinking', storageKey: 'pkr_result_overthinking', url: '/p/tes-tipe-overthinking-gratis.html' }, { slug: 'people_pleaser', label: 'Tes Tipe People Pleaser', storageKey: 'pkr_result_people_pleaser', url: '/p/tes-tipe-people-pleaser-gratis.html' }, { slug: 'red_flag', label: 'Peta Pola Red Flag', storageKey: 'pkr_result_red_flag', url: '/p/tes-pola-red-flag-gratis.html' }, { slug: 'money_mindset', label: 'Kepribadian Finansial', storageKey: 'pkr_result_money_mindset', url: '/p/tes-kepribadian-finansial-money-mindset.html' }, { slug: 'peta_pola_diri', label: 'Peta Pola Diri (Attachment)', storageKey: 'pkr_result_peta_pola_diri', url: '/p/tes-attachment-style-dan-inner-child.html', dual: true }, { slug: 'pemicu_cemas', label: 'Peta Pemicu Cemas', storageKey: 'pkr_result_pemicu_cemas', url: '/p/tes-tipe-cemas-berlebihan-gratis.html' }, { slug: 'roda_emosi', label: 'Peta Emosi Harian', storageKey: 'pkr_result_roda_emosi', url: '/p/cek-roda-emosi-harian-gratis.html', isEmotion: true } ]; /* ---------- 6 POLA INTI ---------- */ var PATTERNS = { kontrol: { name: 'Kontrol', desc: 'Kamu merasa lebih aman kalau semuanya bisa diprediksi dan dikendalikan. Bukan karena kamu kaku, tapi karena ketidakpastian pernah terasa berbahaya, jadi otakmu belajar mengunci kendali sebagai cara bertahan.' }, antisipasi: { name: 'Antisipasi Ancaman', desc: 'Otakmu terbiasa membaca kemungkinan buruk lebih dulu, sebelum sesuatu benar-benar terjadi. Ini bukan berlebihan, ini cara pikiranmu bersiap-siap supaya tidak kaget kalau hal buruk itu datang.' }, validasi: { name: 'Kejar Validasi', desc: 'Rasa berhargamu sering terasa bergantung pada pengakuan, penerimaan, atau pencapaian yang terlihat orang lain. Bukan karena kamu haus pujian, tapi karena di suatu titik, itu adalah cara paling nyata untuk merasa layak.' }, jagadamai: { name: 'Jaga Damai', desc: 'Kamu lebih sering meredam dirimu sendiri daripada memicu ketegangan. Diam atau mengalah terasa lebih aman, karena konflik pernah terasa seperti ancaman yang harus dihindari dengan segala cara.' }, menghindar: { name: 'Menghindar & Jaga Jarak', desc: 'Kamu melindungi diri dengan menjauh, bukan mendekat. Bergantung ke orang lain, uang, atau situasi tertentu terasa lebih berisiko dibanding berjarak dan mengandalkan diri sendiri.' }, polaberulang: { name: 'Pola Berulang dalam Relasi', desc: 'Ada pola lama yang terus kebawa ke hubungan-hubungan barumu, meski situasinya sudah berbeda. Bukan karena kamu tidak belajar, tapi karena pola itu pernah terasa seperti satu-satunya bentuk kedekatan yang kamu kenal.' } }; /* ---------- PEMETAAN TIPE ASLI SETIAP TOOLS -> POLA INTI ---------- */ /* disusun dari mekanisme asli tiap tipe, bukan cuma nama. lihat catatan riset internal. */ var PATTERN_MAP = { 'Si Analis': ['kontrol'], 'Cemas Kontrol': ['kontrol'], 'Si Waspada Berlebih': ['kontrol'], 'Si Peramal': ['antisipasi'], 'Cemas Antisipatif': ['antisipasi'], 'Cemas Somatik': ['antisipasi'], 'Si Pencari Kepastian': ['antisipasi'], 'Si Pengejar Restu': ['validasi'], 'Si Pembaca Pikiran': ['validasi'], 'Si Penghindar Penolakan': ['validasi'], 'Cemas Sosial': ['validasi'], 'Si Pengejar Validasi': ['validasi'], 'Si Pengejar Tanpa Henti': ['validasi', 'antisipasi'], 'Anak Baik': ['validasi'], 'Si Pengejar Prestasi': ['validasi'], 'Si Penyelamat': ['validasi'], 'Si Penjaga Damai': ['jagadamai'], 'Si Pembaca Suasana': ['jagadamai'], 'Si Penjaga Kedamaian': ['jagadamai'], 'Si Penghindar': ['menghindar'], 'Si Mandiri Sejak Dini': ['menghindar'], 'Si Penjaga Jarak': ['menghindar'], 'Si Pencari yang Familiar': ['polaberulang'], 'Si Takut Sendirian': ['polaberulang'], 'Si Pemaaf Berulang': ['polaberulang'], 'Si Tarik-Ulur': ['polaberulang'], 'Si Tenang yang Percaya': [] }; /* sinyal penguat dari emosi harian, bobot lebih ringan dari tools bertipe */ var EMOTION_HINT = { 'Cemas': 'antisipasi', 'Khawatir': 'antisipasi', 'Takut': 'antisipasi', 'Waspada': 'antisipasi', 'Ngeri': 'antisipasi', 'Gugup': 'antisipasi', 'Marah': 'kontrol', 'Kesal': 'kontrol', 'Jengkel': 'kontrol', 'Geram': 'kontrol' }; /* ---------- BACA DATA ---------- */ function safeGet(key) { try { var raw = localStorage.getItem(key); if (!raw) return null; return JSON.parse(raw); } catch (e) { return null; } } function readAllResults() { var out = []; for (var i = 0; i < TOOLS.length; i++) { var t = TOOLS[i]; var val = safeGet(t.storageKey); if (val && val.type) out.push({ tool: t, data: val }); } return out; } /* ---------- HITUNG SKOR POLA ---------- */ function computePatternScores(results) { var score = { kontrol: 0, antisipasi: 0, validasi: 0, jagadamai: 0, menghindar: 0, polaberulang: 0 }; var evidence = { kontrol: [], antisipasi: [], validasi: [], jagadamai: [], menghindar: [], polaberulang: [] }; results.forEach(function (r) { if (r.tool.isEmotion) { var hint = EMOTION_HINT[r.data.type]; if (hint) { score[hint] += 0.5; evidence[hint].push(r.tool.label + ' (sinyal emosi: ' + r.data.type + ')'); } return; } var keysToCheck = [r.data.type]; if (r.tool.dual && r.data.context) keysToCheck.push(r.data.context); keysToCheck.forEach(function (typeStr) { var tags = PATTERN_MAP[typeStr]; if (!tags) return; tags.forEach(function (tag) { score[tag] += 1; evidence[tag].push(r.tool.label + ': ' + typeStr); }); }); }); var ranked = Object.keys(score).sort(function (a, b) { return score[b] - score[a]; }); return { score: score, evidence: evidence, ranked: ranked }; } /* ---------- RENDER ---------- */ function esc(s) { var d = document.createElement('div'); d.textContent = s; return d.innerHTML; } function renderEmpty(root) { root.innerHTML = '<div class="pd-glow-a"></div><div class="pd-glow-b"></div>' + '<div class="pd-inner">' + '<div class="pd-badge">Psikorealis Tools Series &middot; 11</div>' + '<svg class="pd-hero" viewBox="0 0 200 160" fill="none">' + heroSvg() + '</svg>' + '<h1 class="pd-title">Peta Diri</h1>' + '<p class="pd-sub">Ini bukan tes baru. Ini tempat semua sisi dirimu dari tools Psikorealis lain berkumpul jadi satu gambaran utuh. Belum ada satu pun hasil yang tersimpan di HP ini, mulai dari salah satu tools di bawah.</p>' + '<div class="pd-empty-cta">' + '<a class="pd-btn pd-btn-primary" href="/p/tes-tipe-overthinking-gratis.html">Mulai dari Overthinking' + ICON.arrow + '</a>' + '</div>' + '<p class="pd-disclaimer">Semua hasil disimpan hanya di browser HP kamu sendiri, tidak pernah dikirim ke server Psikorealis manapun.</p>' + '</div>'; } function renderMain(root, results, patternInfo) { var total = TOOLS.length; var done = results.length; var pct = Math.round((done / total) * 100); var html = '<div class="pd-glow-a"></div><div class="pd-glow-b"></div><div class="pd-inner">'; html += '<div class="pd-badge">Psikorealis Tools Series &middot; 11</div>'; html += '<h1 class="pd-title">Peta Diri</h1>'; html += '<p class="pd-sub">Rangkuman semua pola yang sudah terpetakan dari tools yang pernah kamu kerjakan di HP ini.</p>'; html += '<div class="pd-progress-wrap"><div class="pd-progress-label"><span>' + done + ' dari ' + total + ' sisi terpetakan</span><span>' + pct + '%</span></div>'; html += '<div class="pd-progress-track"><div class="pd-progress-fill" style="width:' + pct + '%"></div></div></div>'; /* pola dominan */ var topTag = patternInfo.ranked[0]; if (patternInfo.score[topTag] > 0) { var top = PATTERNS[topTag]; html += '<div class="pd-pattern-block"><div class="pd-pattern-eyebrow">Pola paling menonjol saat ini</div>'; html += '<div class="pd-pattern-name">' + esc(top.name) + '</div>'; html += '<p class="pd-pattern-desc">' + esc(top.desc) + '</p>'; html += '<div class="pd-pattern-evidence">'; patternInfo.evidence[topTag].forEach(function (ev) { html += '<div>' + ICON.spark + '<span>' + esc(ev) + '</span></div>'; }); html += '</div></div>'; /* pola kedua kalau skornya juga cukup tinggi dan bukan skor 0 */ var secondTag = patternInfo.ranked[1]; if (secondTag && patternInfo.score[secondTag] >= 1 && patternInfo.score[secondTag] >= patternInfo.score[topTag] * 0.6) { var second = PATTERNS[secondTag]; html += '<div class="pd-emotion-note">' + ICON.leaf + '<span>Pola <strong>' + esc(second.name) + '</strong> juga cukup kuat muncul, kamu mungkin mengalami dua pola ini berjalan bersamaan.</span></div>'; } } /* daftar hasil yang sudah ada */ if (results.length) { html += '<div class="pd-section-title">Hasil yang sudah terpetakan</div><div class="pd-card-list">'; results.forEach(function (r, idx) { if (r.tool.isEmotion) { html += '<div class="pd-card" style="animation-delay:' + (idx * 0.06) + 's"><div class="pd-card-head">' + ICON.leaf + '<span class="pd-card-tool">' + esc(r.tool.label) + '</span></div><div class="pd-card-type">' + esc(r.data.type) + '</div><div class="pd-card-ctx">Emosi yang paling terakhir kamu catat</div></div>'; } else { var ctxLine = r.data.context ? r.data.context : ''; html += '<div class="pd-card" style="animation-delay:' + (idx * 0.06) + 's"><div class="pd-card-head">' + ICON.check + '<span class="pd-card-tool">' + esc(r.tool.label) + '</span></div><div class="pd-card-type">' + esc(r.data.type) + '</div>' + (ctxLine ? '<div class="pd-card-ctx">' + esc(ctxLine) + '</div>' : '') + '</div>'; } }); html += '</div>'; } /* tools yang belum dikerjakan */ var missing = TOOLS.filter(function (t) { return !results.some(function (r) { return r.tool.slug === t.slug; }); }); if (missing.length) { html += '<div class="pd-section-title">Belum terpetakan</div><div class="pd-card-list">'; missing.forEach(function (t, idx) { var href = t.url || '#'; html += '<a class="pd-card-missing" href="' + href + '" style="animation-delay:' + (idx * 0.06) + 's"><span class="pd-card-type">' + esc(t.label) + '</span><span class="pd-arrow">' + ICON.arrow + '</span></a>'; }); html += '</div>'; } html += '<div class="pd-btn-row">'; html += '<button class="pd-btn pd-btn-primary" id="pd-download-btn">Unduh Peta Diri</button>'; html += '<button class="pd-btn pd-btn-ghost" id="pd-import-btn">Impor Peta Diri</button>'; html += '</div><input type="file" id="pd-import-file" accept="application/json">'; html += '<p class="pd-disclaimer">Semua data di halaman ini disimpan hanya di browser HP kamu, tidak pernah dikirim atau disimpan di server Psikorealis. Hapus riwayat browser berarti data ini juga ikut hilang, gunakan tombol unduh kalau mau menyimpannya sebagai cadangan.</p>'; html += '</div>'; root.innerHTML = html; bindActions(results); } function heroSvg() { /* visual peta konstelasi sederhana, titik-titik yang saling terhubung jadi satu peta */ return '<circle cx="40" cy="120" r="5" fill="#FF2D7A"/><circle cx="90" cy="40" r="5" fill="#FF2D7A"/>' + '<circle cx="150" cy="70" r="5" fill="#FF2D7A"/><circle cx="170" cy="130" r="5" fill="#FF2D7A"/>' + '<circle cx="110" cy="110" r="7" fill="#fff"/><circle cx="60" cy="60" r="4" fill="#C2185B"/>' + '<path d="M40 120L60 60L90 40L110 110L150 70L170 130L110 110L40 120" stroke="#8E0E3A" stroke-width="1.4" fill="none" opacity=".7"/>'; } /* ---------- AKSI TOMBOL ---------- */ function bindActions(results) { var dlBtn = document.getElementById('pd-download-btn'); var impBtn = document.getElementById('pd-import-btn'); var impFile = document.getElementById('pd-import-file'); if (dlBtn) dlBtn.addEventListener('click', function () { var payload = {}; TOOLS.forEach(function (t) { var v = safeGet(t.storageKey); if (v) payload[t.storageKey] = v; }); var blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' }); var a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'peta-diri-psikorealis.json'; document.body.appendChild(a); a.click(); document.body.removeChild(a); }); if (impBtn) impBtn.addEventListener('click', function () { impFile.click(); }); if (impFile) impFile.addEventListener('change', function (e) { var file = e.target.files[0]; if (!file) return; var reader = new FileReader(); reader.onload = function (ev) { try { var payload = JSON.parse(ev.target.result); Object.keys(payload).forEach(function (key) { localStorage.setItem(key, JSON.stringify(payload[key])); }); location.reload(); } catch (err) { alert('File Peta Diri tidak valid atau rusak.'); } }; reader.readAsText(file); }); } /* ---------- INIT ---------- */ function init() { var root = document.getElementById('peta-app'); if (!root) return; var results = readAllResults(); if (!results.length) { renderEmpty(root); return; } var patternInfo = computePatternScores(results); renderMain(root, results, patternInfo); if (typeof gtag === 'function') { var topTag = patternInfo.ranked[0]; gtag('event', 'hasil_tes', { nama_tool: 'peta_diri', kombinasi: patternInfo.score[topTag] > 0 ? PATTERNS[topTag].name : 'belum_ada_pola' }); } } if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init); else init(); })();